SELECT p.post_id AS id, p.post_type AS postType, c.cat_name AS "category.name", p.post_title AS title, p.post_content AS content, p.post_top AS postTop, p.created_date AS createdDate, p.updated_date AS updatedDate, p.view_count AS viewCount FROM movmov_cs_posts p JOIN movmov_content_categories c ON p.cat_id = c.cat_id WHERE p.post_type = #{postType}
AND p.cat_id = #{catId}
ORDER BY p.post_top ASC, p.created_date DESC

SELECT f.faq_id AS id, f.faq_title AS title, f.faq_content AS content, c.cat_name AS "category.name" FROM movmov_cs_faq f JOIN movmov_content_categories c ON f.cat_id = c.cat_id
c.cat_id = #{catId}
AND f.faq_title LIKE #{keyword}
ORDER BY f.faq_id ASC OFFSET #{offset} ROWS FETCH NEXT #{rows} ROWS ONLY

SELECT COUNT(*) FROM movmov_cs_faq f JOIN movmov_content_categories c ON f.cat_id = c.cat_id
c.cat_id = #{catId}
AND f.faq_title LIKE #{keyword}
